#include <bits/stdc++.h> 
using namespace std;
const int N=305;
int n,m,dp[N][N];
vector<int> g[N];
void dfs(int u)
{
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		dfs(v);
		for(int j=m;j>=1;j--)
		{
			for(int k=0;k<j;k++)
			{
				dp[u][j]=max(dp[u][j-k]+dp[v][k],dp[u][j]);
			}
		}
	}
}
int main()
{
	cin>>n>>m;
	m++;
	for(int i=1;i<=n;i++)
	{
		int f;
		cin>>f>>dp[i][1];
		g[f].push_back(i);
	}
	dfs(0);
	cout<<dp[0][m];
	return 0;
}
